// Número do pedido PD que você deseja buscar
const numeroBusca = "000000003120";  // <-- troque aqui

// Garante que pega o content no formato certo
const content =
  ($json && Array.isArray($json.content) && $json.content) ||
  (Array.isArray($json) && $json[0] && Array.isArray($json[0].content) && $json[0].content) ||
  [];

// Busca apenas se for PD
const resultado = content.find(
  pedido => pedido.numeroDocumento === numeroBusca && pedido.especieDocumento === "PD"
);

return [
  {
    json: resultado || { mensagem: "Pedido PD não encontrado", numero: numeroBusca }
  }
];

const content =
  ($json && Array.isArray($json.content) && $json.content) ||
  (Array.isArray($json) && $json[0] && Array.isArray($json[0].content) && $json[0].content) ||
  [];

const vendedores = {}; // estrutura: { [codigoVendedor]: { OR:Set, PD:Set, ORparaPD:Map } }

for (const pedido of content) {
  const numero = pedido?.numeroDocumento;
  const especie = pedido?.especieDocumento;
  const vendedor = pedido?.codigoVendedor || "SEM_VENDEDOR";

  if (!numero || !especie) continue;

  // garante a estrutura para o vendedor
  if (!vendedores[vendedor]) {
    vendedores[vendedor] = {
      OR: new Set(),
      PD: new Set(),
      ORparaPD: new Map()
    };
  }

  // adiciona OR ou PD
  if (especie === "OR") vendedores[vendedor].OR.add(numero);
  if (especie === "PD") vendedores[vendedor].PD.add(numero);

  // verifica conversão OR → PD nos itens
  if (pedido.itens) {
    for (const item of pedido.itens) {
      if (item.especieFaturamento === "PD" && item.numeroFaturamento) {
        vendedores[vendedor].ORparaPD.set(numero, item.numeroFaturamento);
      }
    }
  }
}

// monta resultado final por vendedor
const resultadoPorVendedor = Object.entries(vendedores).map(([vendedor, dados]) => {
  const pedidosOR = Array.from(dados.OR);
  const pedidosPD = Array.from(dados.PD);
  const OR_viraram_PD = Array.from(dados.ORparaPD.entries()).map(([or, pd]) => ({
    numeroDocumento: or,
    numeroFaturamento: pd,
    especieFaturamento: "PD"
  }));

  return {
    codigoVendedor: vendedor,
    pedidosOR,
    pedidosPD,
    OR_viraram_PD,
    totais: {
      OR: pedidosOR.length,
      PD: pedidosPD.length,
      OR_convertidos: OR_viraram_PD.length
    }
  };
});

return [{ json: { vendedores: resultadoPorVendedor } }];

